import json, re
db = json.load(open('scripts/refactoring/migration_from_v2_to_v3_db.json'))
print('Total keys (components + ALL):', len(db))
print('First 12 keys:', list(db.keys())[:12])
print('ALL entries:', len(db.get('#ALL#', {})))

def is_case_only(a, b):
    return a.lower().replace('_', '') == b.lower().replace('_', '')

examples = []
for comp, m in db.items():
    if comp == '#ALL#':
        continue
    for a, b in m.items():
        if not is_case_only(a, b):
            examples.append((comp, a, b))
print('Non-case-only renames (real symbol changes):', len(examples))
print()
for comp, a, b in examples[:22]:
    print('  [%s] %-30s -> %s' % (comp, a, b))

# how many entries are pure identity (a == b)?
ident = 0
total = 0
for comp, m in db.items():
    for a, b in m.items():
        total += 1
        if a == b:
            ident += 1
print()
print('Total entries:', total, 'identity (a==b):', ident)

